  // Use sqlgen::write to insert records
  sqlgen::write(conn, records).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Determine the table type based on table name
  if (table_name == "Student") {
    using TableType = Student;
    auto condition = "SNo"_c == record_id;
    auto delete_stmt = sqlgen::delete_from<TableType> | sqlgen::where(condition);
    delete_stmt(conn).value();
  } else if (table_name == "Course") {
    using TableType = Course;
    auto condition = "CID"_c == std::stoul(record_id);
    auto delete_stmt = sqlgen::delete_from<TableType> | sqlgen::where(condition);
    delete_stmt(conn).value();
  } else if (table_name == "Score") {
    using TableType = Score;
    auto condition = "ScID"_c == std::stoul(record_id);
    auto delete_stmt = sqlgen::delete_from<TableType> | sqlgen::where(condition);
    delete_stmt(conn).value();
