 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Create Course and Enrollment tables
  conn.execute(R"(
    CREATE TABLE Course (
      course_id INTEGER PRIMARY KEY,
      title TEXT NOT NULL
    )
  )").value();

  conn.execute(R"(
    CREATE TABLE Enrollment (
      enrollment_id INTEGER PRIMARY KEY,
      course_id INTEGER NOT NULL,
      grade REAL
    )
  )").value();

  // 3. Query the database with left join, group by, and aggregations
  auto result = sqlgen::select_from<Course, "c">(
      "title"_c,
      sqlgen::count("enrollment_id"_e).as<"student_count">(),
      sqlgen::avg("grade"_e).as<"avg_grade">()
