 */
bool migration_add_column() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Generate current and target table structures
  auto current_table = sqlgen::transpilation::to_create_table<User>();
  auto target_table = sqlgen::transpilation::to_create_table<UserAfter>();

  // 3. Extract column names for comparison
  auto get_column_names = [](const auto& table) {
    return table.columns | std::ranges::views::transform([](const auto& col) { 
      return col.name; 
    });
  };

  auto current_cols = get_column_names(current_table);
  auto target_cols = get_column_names(target_table);

  // 4. Determine which columns need to be added
  std::vector<std::string> columns_to_add;
  for (const auto& target_col : target_cols) {
    if (std::find(current_cols.begin(), current_cols.end(), target_col) == current_cols.end()) {
      columns_to_add.push_back(target_col);
