  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

using namespace sqlgen::literals;

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create temporary tables
  conn.execute("CREATE TEMPORARY TABLE Department (department_id INT PRIMARY KEY, department_name VARCHAR(100) NOT NULL, location VARCHAR(100))").value();
  conn.execute("CREATE TEMPORARY TABLE Employee (employee_id INT PRIMARY KEY, department_id INT, first_name VARCHAR(50) NOT NULL, last_name VARCHAR(50) NOT NULL, salary FLOAT NOT NULL)").value();

  // Insert data using sqlgen's insert_into function
  sqlgen::insert_into<Department>(depts)(conn).value();
  sqlgen::insert_into<Employee>(emps)(conn).value();

  // Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                    | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
                    | sqlgen::to<std::vector<JoinResult>>;
  auto inner_results = inner_query(conn).value();

  // Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">("first_name"_t1, "last_name"_t1, "salary"_t1, "department_name"_t2)
                    | sqlgen::left_join<Department, "d">("department_id"_t1 == "department_id"_t2)
                    | sqlgen::to<std::vector<JoinResult>>;
  auto left_results = left_query(conn).value();

  // Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                    | sqlgen::right_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
                    | sqlgen::to<std::vector<JoinResult>>;
  auto right_results = right_query(conn).value();

  // Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                    | sqlgen::full_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
                    | sqlgen::to<std::vector<JoinResult>>;
  auto full_results = full_query(conn).value();

  // Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = std::move(inner_results),
      .left_join_results = std::move(left_results),
      .right_join_results = std::move(right_results),
      .full_join_results = std::move(full_results)
  };
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Temporary Tables**: Creates temporary tables using raw SQL execution via `conn.execute()`

3. **Data Insertion**: Uses `sqlgen::insert_into()` function to insert Department and Employee data

4. **Query Building**: Uses sqlgen's fluent interface with `operator|` to build complex queries:
   - `select_from()` starts the query with table selection
   - `inner_join()`, `left_join()`, `right_join()`, `full_join()` perform different join types
   - Column references use the literal syntax (`"column_name"_t1`) with table aliases

5. **Result Handling**: Uses `sqlgen::to<std::vector<JoinResult>>` to specify the return type and extract results

6. **Comprehensive Analysis**: Returns all four join results in a structured `JoinAnalysis` object

The implementation follows sqlgen's principles of using a fluent, type-safe interface for database operations while meeting all the specified requirements for join operations and result analysis.

